class AuthenticatedApiClient {
  constructor(oauthClient, baseUrl) {
    this.oauthClient = oauthClient;
    this.baseUrl = baseUrl;
  }

  async request(endpoint, options = {}) {
    let accessToken;

    try {
      accessToken = await this.oauthClient.getValidAccessToken();
    } catch (error) {
      throw new Error(`Authentication required: ${error.message}`);
    }

    if (!accessToken) {
      throw new Error('No access token available.');
    }

    const url = `${this.baseUrl}${endpoint}`;
    const headers = {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
      'Content-Type': 'application/json',
    };

    let response = await fetch(url, { ...options, headers });

    // If we get a 401, try refreshing the token once and retry
    if (response.status === 401) {
      try {
        await this.oauthClient.refreshAccessToken();
        accessToken = await SecureTokenStorage.getAccessToken();

        headers.Authorization = `Bearer ${accessToken}`;
        response = await fetch(url, { ...options, headers });
      } catch (refreshError) {
        throw new Error(`Re-authentication required: ${refreshError.message}`);
      }
    }

    return response;
  }

  async get(endpoint, options = {}) {
    return this.request(endpoint, { ...options, method: 'GET' });
  }

  async post(endpoint, data, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'POST',
      body: JSON.stringify(data),
    });
  }
}

