// React Context for Auth State
// ============================================================

const AuthContext = createContext(null);

const oauthClient = new OAuthClient(OAUTH_CONFIG);
const apiClient = new AuthenticatedApiClient(oauthClient, 'https://api.example.com');

WebBrowser.maybeCompleteAuthSession();

function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState(null);

  useEffect(() => {
    checkExistingAuth();
  }, []);

  const checkExistingAuth = async () => {
    try {
      const token = await SecureTokenStorage.getAccessToken();
      const isExpired = await SecureTokenStorage.isTokenExpired();

      if (token && !isExpired) {
        setIsAuthenticated(true);
        await fetchUserProfile();
      } else if (token && isExpired) {
        try {
          await oauthClient.refreshAccessToken();
          setIsAuthenticated(true);
          await fetchUserProfile();
        } catch {
          await SecureTokenStorage.clearTokens();
          setIsAuthenticated(false);
        }
      } else {
        setIsAuthenticated(false);
      }
    } catch (error) {
      console.error('Auth check failed:', error);
      setIsAuthenticated(false);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchUserProfile = async () => {
    try {
      const response = await apiClient.get('/userinfo');
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
      }
    } catch (error) {
      console.error('Failed to fetch user profile:', error);
    }
  };

  const login = useCallback(async () => {
    try {
      setIsLoading(true);

      const { authUrl, state } = await oauthClient.startAuthorizationFlow();

      const result = await WebBrowser.openAuthSessionAsync(
        authUrl,
        OAUTH_CONFIG.redirectUri
      );

      if (result.type === 'success' && result.url) {
        const url = new URL(result.url);
        const code = url.searchParams.get('code');
        const returnedState = url.searchParams.get('state');
        const error = url.searchParams.get('error');

        if (error) {
          const errorDescription = url.searchParams.get('error_description');
          throw new Error(errorDescription || error);
        }

        if (returnedState !== state) {
          throw new Error('State mismatch. Possible CSRF attack.');
        }

        if (!code) {
          throw new Error('No authorization code received.');
        }

        await oauthClient.exchangeCodeForTokens(code);
        setIsAuthenticated(true);
        await fetchUserProfile();
      } else if (result.type === 'cancel') {
        console.log('User cancelled authentication');
      }
    } catch (error) {
      console.error('Login failed:', error);
      Alert.alert('Login Failed', error.message || 'An error occurred during login.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  const logout = useCallback(async () => {
    try {
      setIsLoading(true);
      await oauthClient.revokeTokens();
      setIsAuthenticated(false);
      setUser(null);
    } catch (error) {
      console.error('Logout failed:', error);
      // Clear local state even if revocation fails
      await SecureTokenStorage.clearTokens();
      setIsAuthenticated(false);
      setUser(null);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const value = {
    isAuthenticated,
    isLoading,
    user,
    login,
    logout,
    apiClient,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

